text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트가 통과할 경우 공개 릴리스 목표 시점은 2026-05-15 15:00 KST이다.",
        "basis": "Seoyeon의 수요일 제안에 대해 Doyun이 스모크 테스트 선행 필요성을 제기했고, 최종 결정으로 금요일 15:00 KST가 확정되었다.",
        "certainty": "confirmed"
      },
      {
        "topic": "packageName mismatch 대응 원칙",
        "decision": "packageName mismatch가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다.",
        "basis": "smoke-theme-pack.mjs에서 mismatch를 무시하자는 제안은 기각되었고, 대신 설정 우선 점검 원칙이 최종 결정되었다.",
        "certainty": "confirmed"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs가 packageName mismatch를 무시하도록 변경한다.",
        "proposed_by": "Hara",
        "result": "rejected",
        "certainty": "confirmed"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "2026-05-13 수요일 릴리스",
        "status": "내부 스트레치 목표",
        "note": "확정 일정이 아니라 내부 목표로만 언급되었다.",
        "certainty": "confirmed"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 절차 검토",
        "state": "2026-05-14까지 가능하면 검토하자는 의견은 있었으나 담당자 배정은 없었다.",
        "certainty": "partial"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로로 인해 릴리스가 지연될 수 있다.",
        "certainty": "confirmed"
      },
      {
        "risk": "README 설치 절차가 최신이 아니면 릴리스 노트가 사용자를 오도할 수 있다.",
        "certainty": "confirmed"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?",
        "status": "unresolved",
        "certainty": "confirmed"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?",
        "status": "unresolved",
        "certainty": "confirmed"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "2026-05-15 10:00 KST",
      "status": "confirmed",
      "source_certainty": "high"
    },
    {
      "owner": "Doyun",
      "task": "실패 시 트리아지 노트를 action_items.md에 작성한다.",
      "due": "2026-05-15 12:00 KST",
      "status": "confirmed",
      "source_certainty": "high"
    },
    {
      "owner": null,
      "task": "README 설치 절차를 검토한다.",
      "due": "2026-05-14 (가능하면)",
      "status": "owner_unassigned",
      "source_certainty": "medium"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로를 확인한다.",
      "due": null,
      "status": "confirmed_no_exact_deadline",
      "source_certainty": "high"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "2026-05-15 10:00 KST까지 Minjun의 스모크 테스트 결과가 공유되었는지 확인한다.",
      "스모크 테스트 실패 시 Doyun의 트리아지 노트가 2026-05-15 12:00 KST까지 action_items.md에 반영되었는지 확인한다.",
      "스모크 결과 공유 이후 Hara의 tarball 경로 점검 결과를 확인한다.",
      "README 설치 절차 검토의 실제 담당자가 지정되었는지 확인한다.",
      "최종 릴리스 승인 권한자와 릴리스 노트의 수요일 스트레치 목표 언급 여부를 후속 결정 항목으로 유지한다."
    ],
    "what_not_to_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 필요 여부",
      "미지정 담당자",
      "명시되지 않은 추가 마감일"
    ]
  },
  "non_invention_rules": [
    "회의 기록에 없는 고객명, 외부 파트너명은 추가하지 않는다.",
    "예산, 보안, 장애, 법무 관련 사실은 언급된 범위를 넘어서 작성하지 않는다.",
    "담당자가 없는 항목에 임의로 owner를 부여하지 않는다.",
    "정확한 마감이 없는 항목에 임의의 due를 넣지 않는다.",
    "확정 결정과 제안, 스트레치 목표, 미해결 질문을 혼합하지 않는다.",
    "fixture에 없는 승인자, 우선순위, 배경 사유를 추론으로 보강하지 않는다."
  ]
}
